import { AgentProject, Tool } from '@azure/ai-projects';
import { VexPipeline } from 'vex-sdk';

const project = await AgentProject.fromConfig('azure-ai-customer-support');
const vex = new VexPipeline({
  projectId: 'cs-001',
  validations: ['pii_filtering', 'policy_compliance']
});

const ticketTool = new Tool({
  name: 'create_ticket',
  description: 'Create support ticket in Dynamics 365',
  func: async (issue: string, customerId: string) => {
    const sanitizedData = await vex.validatePII({ issue, customerId });
    const ticket = await project.crm.createTicket(sanitizedData);
    return `Ticket ${ticket.id} created successfully`;
  }
});

await thread.addTool(ticketTool);

const orderLookupTool = new Tool({
  name: 'lookup_order',
  description: 'Lookup customer order status',
  func: async (orderId: string) => {
    const orderData = await project.crm.queryOrder(orderId);
    // Vex ensures no sensitive pricing/PII exposed
    const safeResponse = await vex.validate_policy({
      data: orderData,
      context: 'order_lookup',
      policies: ['no_pricing', 'no_pii']
    });
    return safeResponse;
  }
});

