from vex_sdk import TokenMonitor

token_monitor = TokenMonitor(max_tokens=128000, model='gpt-4o')

@vex_pipeline.hook('before_execution')
def check_token_limits(context):
    thread_tokens = context['thread'].token_count
    if token_monitor.warning(thread_tokens):
        # Summarize conversation history
        context['thread'].summarize_history()
        context['escalation'] = 'token_limit_approaching'
    return context

import { VexPipeline, VexGuardrail } from 'vex-sdk';

const freshnessGuardrail = new VexGuardrail('data_freshness');

vexPipeline.on('after_retrieval', async (context) => {
  const retrievals = context.retrievalResults;
  const validated = await freshnessGuardrail.validate({
    sources: retrievals,
    maxAgeDays: 30, // Enterprise policy
    context: 'customer_support'
  });

  if (!validated.allFresh) {
    context.escalation = 'stale_data_detected';
    context.fallback = 'Please check our latest documentation or contact specialist support';
  }

  return context;
});
